import { Component, OnInit } from '@angular/core';

@Component({
  selector: 'app-tier-list',
  templateUrl: './tier-list.component.html',
  styleUrls: ['./tier-list.component.scss'],
})
export class TierListComponent  implements OnInit {
  //Картинки в наличии
  sourceImages = [
    { label: '', url: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQBwvyWwfKTAB1aeKELlHhR-zyFGxRmeK36cw&s' },
    { label: '', url: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTNqaosVRQqucYyO9-mXbUs7AdGyNp48xN4bA&s' },
    { label: '', url: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcR_5L3HYm7dJ9004aLXtmBIESJsDoiVYZm7iQ&s' },
    { label: '', url: 'data:image/jpeg;base64,' },
    { label: '', url: 'data:image/jpeg;base64,' },
    { label: '', url: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRJ8sYl7iydEthfz7iyJEW-g4G1ewLucMvmdQ&s' },
    { label: '', url: 'data:image/jpeg;base64,' },
    { label: '', url: 'data:image/jpeg;base64,' },       
    { label: '', url: 'data:image/jpeg;base64,' }, 
    { label: '', url: 'data:image/jpeg;base64,' },  
    { label: '', url: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTlALYZCCuIKBI212CKkbUke9QPe0swumIWcQ&s' }, 
    { label: '', url: 'data:image/jpeg;base64,' },   
    { label: '', url: 'data:image/jpeg;base64,' },   
  ];

  //Уже в рядах
  placedItems: any[] = [];

  //Перетаскивоемое
  dragImage: any = null;

  //помним что тащим
  onDragStart(img: any) {
    this.dragImage = img;
  }

  // Сбросить на ряд
  onDrop(event: any, tierLabel: string) {
    event.preventDefault();
    if (this.dragImage) {
      this.placedItems.push({
        id: Date.now(),
        tierId: tierLabel,
        url: this.dragImage.url,
        label: this.dragImage.label
      });
      this.dragImage = null;
    }
  }

  // Получить картинки в ряду
  getItemsByTier(tierLabel: string) {
    return this.placedItems.filter(item => item.tierId === tierLabel);
  }

  // Удалить картинку
  removeItem(itemId: number) {
    this.placedItems = this.placedItems.filter(item => item.id !== itemId);
  }

 downloadImage()
 {
  const input = document.createElement('input');
  input.type = 'file';
  input.accept= 'image/*';
  input.onchange = (event: any)=> 
  { const file = event.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e: any)=>{
        const newImage = {
          label: 'ur image',
          url: e.target.result
        };
        this.sourceImages.push(newImage);
      }
      reader.readAsDataURL(file);
    }   

  };
  input.click()
 }







  constructor() { }

  ngOnInit() {}

}
